// // This module is designed to store a 32-bit input value (RD1) and output it (A) on the falling edge of a clock signal (clk). The register updates its output value with the input value whenever the clock transitions from high to low.
module top_module(RD1,clk,A);input [31:0] RD1;
  input clk;
  output [31:0] A;

  reg [31:0] a;
  assign A=a;

  always @ (posedge clk)
  begin
    a<=RD1;
  end

endmodule
